SELECT p.position, COUNT(p.player_id) AS total_players
FROM players p
WHERE p.salary > (
    SELECT AVG(salary) FROM players
)
GROUP BY p.position;

SELECT full_name
FROM players
WHERE salary > (SELECT AVG(salary) FROM players);

SELECT player_id, draft_year
FROM drafts
WHERE draft_year = 2011;

SELECT AVG(salary) AS avg_salary
FROM players
WHERE player_status = 'active';

SELECT COUNT(*)
FROM drafts
WHERE draft_team_id = 1 AND draft_round = 1;
